// text.js from the CCGL9074 engine: a pure-type scene with inline emphasis
// (**bold**, __underline__, ==highlight==). Adapted to accept a DOM element.
import { d3 } from './deps.js';
import { dur, globalReveal } from './utils.js';

function enrich(txt){
  if (!txt) return '';
  let s = String(txt);
  s = s
    .replace(/\*\*(.+?)\*\*/g, '<span class="fx fx-bold">$1</span>')
    .replace(/__(.+?)__/g, '<span class="fx fx-underline">$1</span>')
    .replace(/==(.+?)==/g, '<span class="fx fx-highlight">$1</span>');
  return s;
}

export function build(sel, props){
  const box = (typeof sel === 'string') ? document.querySelector(sel) : sel;
  if (!box) return;
  const scene = box.closest('.scene');

  box.style.textAlign = props.align || 'center';

  const kicker = props.kicker ? `<div class="text-kicker">${props.kicker}</div>` : '';
  const titleRaw = props.titleHTML ?? (props.title || '');
  const bodyRaw = props.bodyHTML || '';

  const titleHTML = titleRaw ? `<h2 class="text-title">${enrich(titleRaw)}</h2>` : '';
  const bodyHTML = bodyRaw ? `<div class="text-body">${enrich(bodyRaw)}</div>` : '';

  box.innerHTML = `${kicker}${titleHTML}${bodyHTML}`;

  globalReveal({
    container: sel,
    fadeSel: d3.select(box),
    fadeMs: dur(450),
    ease: d3.easeCubicOut,
    animateFinal(){
      if (scene) scene.classList.add('fx-on');
      box.classList.add('revealed');
      box.classList.add('fx-on');
      const rising = Array.from(box.querySelectorAll('.fx-highlight, .fx-underline, .fx-bold'));
      rising.forEach((el, i) => { el.style.transitionDelay = (90 * i) + 'ms'; });
    }
  });
}
